# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

from selenium import webdriver
import boto3
from io import BytesIO

def take_screenshot(url):
    # Set up headless Chrome
    options = webdriver.ChromeOptions()
    options.add_argument('--headless')
    options.add_argument('--no-sandbox')
    options.add_argument('--disable-dev-shm-usage')

    driver = webdriver.Chrome(options=options)
    try:
        driver.get(url)
        screenshot = driver.get_screenshot_as_png()

        # Store the screenshot in S3
        s3_client = boto3.client('s3', aws_access_key_id='YOUR_ACCESS_KEY',
                                  aws_secret_access_key='YOUR_SECRET_KEY')
        bucket_name = 'your-s3-bucket'
        file_name = f"screenshots/{url.split('//')[-1].split('/')[0]}.png"

        s3_client.upload_fileobj(BytesIO(screenshot), bucket_name, file_name)
        print(f'Screenshot saved to {bucket_name}/{file_name}')
    finally:
        driver.quit()

# Example usage
take_screenshot('https://www.example.com')